INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "アヤネ", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 24001, 2, 2, 401, 102301, 0.0, 0.0, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "アヤネ", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 2.21, 24002, 2, 1, 402, 102301, 0.0, 0.0, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "アヤネ", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 24003, 2, 2, 403, 102301, 0.0, 0.0, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "アサヒ", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 1.99, 24004, 1, 2, 701, 192201, 0.0, 0.0, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "アサヒ", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 2.21, 24005, 2, 1, 702, 192201, 0.0, 0.0, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "アサヒ", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 3.33, 24006, 1, 2, 703, 192201, 0.0, 0.0, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "部員３", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 24007, 2, 2, 801, 192301, 0.0, 0.0, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "部員３", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 2.68, 24008, 2, 1, 802, 192301, 0.0, 0.0, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "部員３", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 24009, 2, 2, 803, 192301, 0.0, 0.0, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 24010, 1, 1, 501, 192501, 0.0, 0.0, "やった！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 24011, 1, 1, 502, 192501, 0.0, 0.0, "勝ったよ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 24012, 1, 1, 503, 192501, 0.0, 0.0, "いい調子！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "ミサト", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 5.33, 24013, 2, 6, 111, 113501, 0.0, 0.0, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "ミサト", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 6.85, 24014, 2, 1, 112, 113501, 0.0, 0.0, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "ミサト", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 3.0, 24015, 2, 1, 113, 113501, 0.0, 0.0, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "ダイチ", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 6.11, 24016, 2, 1, 611, 192401, 0.0, 0.0, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "ダイチ", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 6.75, 24017, 2, 1, 612, 192401, 0.0, 0.0, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "ダイチ", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 24018, 2, 2, 613, 192401, 0.0, 0.0, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "ハツネ", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 4.52, 24019, 1, 2, 211, 113401, 0.0, 0.0, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "ハツネ", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 3.89, 24020, 1, 2, 212, 113401, 0.0, 0.0, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "ハツネ", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 13.49, 24021, 2, 1, 213, 113401, 0.0, 0.0, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "カヤ", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 3.17, 24022, 2, 1, 311, 106501, 0.0, 0.0, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "カヤ", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 4.42, 24023, 2, 1, 312, 106501, 0.0, 0.0, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "カヤ", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 2.89, 24024, 1, 6, 313, 106501, 0.0, 0.0, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "アヤネ", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 3.71, 24025, 3, 4, 421, 102301, 0.0, 0.0, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "アサヒ", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 5.1, 24026, 1, 2, 721, 192201, 0.0, 0.0, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "部員３", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 4.34, 24027, 3, 1, 821, 192301, 0.0, 0.0, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 24028, 1, 1, 521, 192501, 0.0, 0.0, "いい勝負だったよ\nまたやろうね");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "ミサト", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 5.62, 24029, 2, 1, 101, 113501, -360.0, 0.0, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "ミサト", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 9.58, 24030, 2, 1, 102, 113501, -360.0, 0.0, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "ミサト", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 0.0, 24031, 2, 2, 103, 113501, -360.0, 0.0, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "ミサト", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 9.13, 24032, 1, 2, 104, 113501, -360.0, 0.0, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 10046, "ミサト", "2030/12/17 14:59:59", "2020/07/31 12:00:00", 8.27, 24033, 2, 1, 105, 113501, -360.0, 0.0, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！");
